#include <stdio.h>

int main() {
  int a = 5, b = 2;
  float result;
  // implicit: int division gives 2, then converted to 2.0
  result = a / b;
  printf("Without cast: %f\n", result);
  // explicit: convert a to float before division
  result = (float) a / b;
  printf("With cast: %f\n", result);
  return 0;
}
